# Terraform - AppSync API のフィールドレベルログを有効にします
resource "aws_appsync_graphql_api" "<example_resource_name>" {
  name                = "<example_resource_name>"
  authentication_type = "AWS_IAM"

  log_config {
    cloudwatch_logs_role_arn = "<cloudwatch_logs_role_arn>" # 重要：CloudWatch へのログ記録を許可します
    field_log_level          = "ERROR"                        # 重要：準拠したフィールドレベルログ
  }
}
```
